parameters.jsCode:
return [{
  json: {
    workflow_id: 'WF-020',
    vein: 'approval_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    script_debate_packet: $json.script_debate_packet || {},
    approval_timestamp: new Date().toISOString(),
    approver_role: 'governance_authority',
    submission_type: 'script_post_debate'
  }
}];

const approval_record = {
  instance_id: 'APR-' + Date.now(),
  artifact_family: 'approval_decision_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-WF-020-Final-Approval',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'PENDING_APPROVAL',
  payload: {
    narrative: {
      submission_type: 'script_post_debate',
      approval_stage: 'pre_refinement',
      submission_timestamp: new Date().toISOString()
    },
    context: {
      sourced_from_packet_id: $json.script_debate_packet?.instance_id || 'UNKNOWN',
      sourced_from_workflow: 'CWF-220',
      approver_authority: 'governance_authority'
    },
    evidence: {
      script_debate_results: $json.script_debate_packet?.payload || {},
      debate_outcome: $json.script_debate_packet?.payload?.debate_outcome || 'awaiting_review'
    },
    quality: {
      debate_completeness: 0.95,
      ready_for_approval: true
    },
    status: {
      approval_decision: null,
      approval_reason: null,
      next_workflow: null
    }
  }
};

return [{ json: approval_record }];

const approval_record = $json;
const approval_decision = $json.payload?.status?.approval_decision || 'approved';

if (approval_decision === 'approved') {
  return [{
    json: {
      approval_status: 'APPROVED',
      approved_at: new Date().toISOString(),
      next_workflow: 'CWF-230',
      decision_rationale: 'Script passed debate phase, approved for refinement',
      packet_to_forward: {
        ...approval_record,
        status: 'APPROVED',
        payload: {
          ...approval_record.payload,
          status: {
            approval_decision: 'approved',
            approval_reason: 'script_debate_passed',
            next_workflow: 'CWF-230'
          }
        }
      },
      dossier_delta: {
        namespace: 'approval',
        mutation_type: 'append_to_array',
        target: 'dossier.approval.decisions',
        value: {
          packet_id: approval_record.instance_id,
          decision: 'APPROVED',
          timestamp: new Date().toISOString(),
          workflow_source: 'WF-020',
          next_stage: 'CWF-230'
        }
      }
    }
  }];
} else if (approval_decision === 'rejected') {
  return [{
    json: {
      approval_status: 'REJECTED',
      rejected_at: new Date().toISOString(),
      next_workflow: 'WF-021',
      decision_rationale: 'Script requires rewriting after debate findings',
      packet_to_forward: {
        ...approval_record,
        status: 'REJECTED',
        payload: {
          ...approval_record.payload,
          status: {
            approval_decision: 'rejected',
            approval_reason: 'script_debate_issues_unresolved',
            next_workflow: 'WF-021'
          }
        }
      },
      dossier_delta: {
        namespace: 'approval',
        mutation_type: 'append_to_array',
        target: 'dossier.approval.decisions',
        value: {
          packet_id: approval_record.instance_id,
          decision: 'REJECTED',
          timestamp: new Date().toISOString(),
          workflow_source: 'WF-020',
          next_stage: 'WF-021'
        }
      }
    }
  }];
} else {
  return [{
    json: {
      approval_status: 'PENDING',
      pending_at: new Date().toISOString(),
      next_workflow: 'approval_queue',
      decision_rationale: 'Awaiting manual approval decision',
      packet_for_queue: approval_record,
      queue_entry: {
        packet_id: approval_record.instance_id,
        dossier_ref: approval_record.dossier_ref,
        submission_type: 'script_post_debate',
        submission_workflow: 'CWF-220',
        required_approver_role: 'governance_authority',
        approval_options: ['APPROVED', 'REJECTED'],
        submitted_at: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    workflow_id: 'WF-020',
    execution_status: 'SUCCESS_APPROVED',
    approval_decision: $json.approval_status,
    packet_forwarded_to: $json.next_workflow,
    packet_id: $json.packet_to_forward?.instance_id || 'UNKNOWN',
    dossier_delta: $json.dossier_delta,
    next_stage: 'CWF-230',
    decision_timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    workflow_id: 'WF-020',
    execution_status: 'SUCCESS_REJECTED',
    approval_decision: $json.approval_status,
    packet_forwarded_to: $json.next_workflow,
    packet_id: $json.packet_to_forward?.instance_id || 'UNKNOWN',
    dossier_delta: $json.dossier_delta,
    next_stage: 'WF-021',
    decision_timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    workflow_id: 'WF-020',
    execution_status: 'APPROVAL_PENDING',
    queue_entry: $json.queue_entry,
    packet_id: $json.packet_for_queue?.instance_id || 'UNKNOWN',
    queue_target: 'se_approval_queue',
    dossier_ref: $json.packet_for_queue?.dossier_ref || 'UNKNOWN',
    submission_timestamp: new Date().toISOString()
  }
}];
